css:
.loader {color: var(--loader-color, #9333ea);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
  width: 45px;
  height: 30px;
  animation: l1 2s infinite linear;
}@keyframes l1{0%,25% {background:linear-gradient(#e50021 0 0) 50% 0/66% 100% no-repeat}25.1%,50% {background:linear-gradient(var(--loader-secondary-color, #f0abfc) 0 0) 0 0/100% 50% no-repeat,linear-gradient(var(--loader-secondary-color, #f0abfc) 0 0) 0 0/33% 100% no-repeat}50.1%,75% {background:linear-gradient(var(--loader-secondary-color, #f0abfc) 0 0) 100% 0/66% 50% no-repeat,linear-gradient(var(--loader-secondary-color, #f0abfc) 0 0) 0 100%/66% 50% no-repeat}75.1%,100% {background:linear-gradient(var(--loader-secondary-color, #f0abfc) 0 0) 0 100%/100% 50% no-repeat,linear-gradient(var(--loader-secondary-color, #f0abfc) 0 0) 50% 0 /33% 50% no-repeat}}
